__d(function(g,r,i,a,m,_e,d){"use strict";Object.defineProperty(_e,'__esModule',{value:!0}),Object.defineProperty(_e,"default",{enumerable:!0,get:function(){return n}});var e,t=r(d[0]),s=(e=t)&&e.__esModule?e:{default:e},n={isVisible:()=>!1,addListener:()=>({remove:()=>{}}),dismiss(){(0,s.default)()},removeAllListeners(){},removeListener(){}}},502,[323]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao996Text",{enumerable:!0,get:function(){return o}});const o="DI\xc1RIO OFICIAL DA UNI\xc3O\nPublicado em: 22/06/2023 | Edi\xe7\xe3o: 117 | Se\xe7\xe3o: 1 | P\xe1gina: 327\n\xd3rg\xe3o: Minist\xe9rio dos Transportes/Conselho Nacional de Tr\xe2nsito\n\nRESOLU\xc7\xc3O CONTRAN N\xba 996, DE 15 DE JUNHO DE 2023\nDisp\xf5e sobre o tr\xe2nsito, em via p\xfablica, de ciclomotores, bicicletas el\xe9tricas e equipamentos de mobilidade individual autopropelidos.\n\nO CONSELHO NACIONAL DE TR\xc2NSITO (CONTRAN), no uso da compet\xeancia que lhe confere o inciso I do art. 12 da Lei n\xba 9.503, de 23 de setembro de 1997, que institui o C\xf3digo de Tr\xe2nsito Brasileiro (CTB), com base no que consta nos autos do processo administrativo n\xba 50000.005947/2021-18, resolve:\n\nCAP\xcdTULO I - DAS DISPOSI\xc7\xd5ES PRELIMINARES\n\nArt. 1\xba Esta Resolu\xe7\xe3o disp\xf5e sobre o tr\xe2nsito, em via p\xfablica, de ciclomotores, bicicletas el\xe9tricas e equipamentos de mobilidade individual autopropelidos.\n\nArt. 2\xba Para efeitos desta Resolu\xe7\xe3o, define-se:\nI - bicicleta: ve\xedculo de propuls\xe3o humana, dotado de duas rodas, n\xe3o sendo, para efeito do CTB, similar \xe0 motocicleta, motoneta e ciclomotor;\nII - equipamento de mobilidade individual autopropelido: equipamento com as seguintes caracter\xedsticas:\na) dotado de uma ou mais rodas;\nb) dotado ou n\xe3o de sistema de autoequil\xedbrio;\nc) provido de motor de propuls\xe3o com pot\xeancia nominal m\xe1xima de at\xe9 1000 W;\nd) velocidade m\xe1xima de fabrica\xe7\xe3o n\xe3o superior a 32 km/h;\ne) largura n\xe3o superior a 70 cm e dist\xe2ncia entre eixos de at\xe9 130 cm;\n\nIII - bicicleta el\xe9trica: ve\xedculo de propuls\xe3o humana, com duas rodas, com as seguintes caracter\xedsticas:\na) provido de motor auxiliar de propuls\xe3o, com pot\xeancia m\xe1xima de at\xe9 1000 W;\nb) provido de sistema que garanta o funcionamento do motor somente quando o condutor pedalar (pedal assistido);\nc) n\xe3o dispor de acelerador ou de qualquer outro dispositivo de varia\xe7\xe3o manual de pot\xeancia; e\nd) velocidade m\xe1xima de propuls\xe3o n\xe3o superior a 32 km/h;\n\nIV - ciclomotor: ve\xedculo de 2 ou 3 rodas, provido de motor de combust\xe3o interna cuja cilindrada n\xe3o exceda a 50 cm\xb3, ou de motor de propuls\xe3o el\xe9trica com pot\xeancia m\xe1xima de 4 kW, e cuja velocidade m\xe1xima de fabrica\xe7\xe3o n\xe3o exceda a 50 km/h;\n\nCAP\xcdTULO II - DOS EQUIPAMENTOS OBRIGAT\xd3RIOS\n\nArt. 3\xba Os equipamentos de mobilidade individual autopropelidos, para circularem, devem ser dotados de:\nI - indicador e/ou dispositivo limitador eletr\xf4nico de velocidade;\nII - campainha; e\nIII - sinaliza\xe7\xe3o noturna, dianteira, traseira e lateral, incorporadas ao equipamento.\nPar\xe1grafo \xfanico. Permite-se a utiliza\xe7\xe3o de aplicativo em smartphone como veloc\xedmetro.\n\nArt. 4\xba As bicicletas el\xe9tricas, para circularem, devem ser dotadas de:\nI - indicador e/ou limitador eletr\xf4nico de velocidade;\nII - campainha;\nIII - sinaliza\xe7\xe3o noturna dianteira, traseira, lateral e nos pedais;\nIV - espelho retrovisor do lado esquerdo; e\nV - pneus em condi\xe7\xf5es m\xednimas de seguran\xe7a.\n\nArt. 5\xba Os ciclomotores devem ser dotados dos equipamentos obrigat\xf3rios estabelecidos no CTB.\n\nCAP\xcdTULO III - DA CIRCULA\xc7\xc3O\n\nArt. 6\xba Cabe ao \xf3rg\xe3o ou entidade com circunscri\xe7\xe3o sobre a via regulamentar a circula\xe7\xe3o nas vias terrestres abertas \xe0 circula\xe7\xe3o p\xfablica.\nArt. 7\xba A circula\xe7\xe3o de bicicletas el\xe9tricas em ciclovias, ciclofaixas e ciclorrotas deve respeitar a velocidade m\xe1xima regulamentada pelo \xf3rg\xe3o.\nArt. 9\xba A circula\xe7\xe3o de equipamentos de mobilidade individual autopropelidos pode ser autorizada:\nI - em \xe1reas de circula\xe7\xe3o de pedestres, limitada a 6 km/h;\nII - em ciclovias, ciclofaixas e ciclorrotas, limitada \xe0 velocidade m\xe1xima regulamentada; e\nIII - em vias com velocidade m\xe1xima regulamentada de at\xe9 40 km/h.\nArt. 11. A circula\xe7\xe3o de bicicletas el\xe9tricas e de equipamentos de mobilidade individual autopropelidos deve seguir as mesmas disposi\xe7\xf5es estabelecidas pelo CTB para a circula\xe7\xe3o de bicicletas.\n\nCAP\xcdTULO IV - DO CADASTRAMENTO, REGISTRO E LICENCIAMENTO\n\nArt. 12. As bicicletas el\xe9tricas e os equipamentos de mobilidade individual autopropelidos n\xe3o s\xe3o sujeitos ao registro, ao licenciamento e ao emplacamento para circula\xe7\xe3o nas vias.\nArt. 13. Para o registro e o licenciamento de ciclomotores, deve ser exigida a apresenta\xe7\xe3o de CAT, c\xf3digo espec\xedfico, nota fiscal e documentos de identifica\xe7\xe3o.\n\nCAP\xcdTULO V - DAS DISPOSI\xc7\xd5ES FINAIS\n\nArt. 19. O descumprimento do disposto nesta Resolu\xe7\xe3o sujeita o infrator, independentemente de outras penalidades, \xe0s seguintes san\xe7\xf5es previstas no CTB:\nI - art. 187, inciso I, quando transitar em local n\xe3o permitido;\nII - art. 193, quando transitar em cal\xe7adas, passeios, ciclovias (exceto autorizado);\nIII - art. 230, inciso IV, quando conduzido sem placa de identifica\xe7\xe3o (ciclomotores);\nIV - art. 230, inciso V, quando conduzir ve\xedculo n\xe3o registrado e licenciado;\nV - art. 244, quando conduzir ciclomotor sem o uso de capacete ou transportar passageiro sem capacete;\nVI - art. 244, \xa7 1\xba, quando transitar com bicicleta el\xe9trica em vias de tr\xe2nsito r\xe1pido ou rodovias;\nVII - art. 244, \xa7 2\xba, quando transitar com ciclomotores nas vias de tr\xe2nsito r\xe1pido ou rodovias.\n\nArt. 22. Esta Resolu\xe7\xe3o entra em vigor em 3 de julho de 2023."},503,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao985Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 985, DE 15 DE DEZEMBRO DE 2022\n\nAprova o Manual Brasileiro de Fiscaliza\xe7\xe3o de Tr\xe2nsito (MBFT).\n\nO CONSELHO NACIONAL DE TR\xc2NSITO (CONTRAN), no uso da compet\xeancia que lhe conferem os incisos I, VII e VIII do art. 12 da Lei n\xba 9.503, de 23 de setembro de 1997, que institui o C\xf3digo de Tr\xe2nsito Brasileiro (CTB), e com base no que consta nos autos do processo administrativo n\xba 50000.034509/2021-39, resolve:\n\nArt. 1\xba Esta Resolu\xe7\xe3o aprova o Manual Brasileiro de Fiscaliza\xe7\xe3o de Tr\xe2nsito (MBFT), que tem por objetivo consolidar as normas e procedimentos a serem adotados pelas autoridades de tr\xe2nsito e seus agentes na fiscaliza\xe7\xe3o do tr\xe2nsito.\n\nArt. 2\xba O MBFT \xe9 de ado\xe7\xe3o obrigat\xf3ria para todas as autoridades de tr\xe2nsito e seus agentes, no \xe2mbito de suas respectivas circunscri\xe7\xf5es.\n\nArt. 3\xba O agente de tr\xe2nsito, ao constatar o cometimento da infra\xe7\xe3o, lavrar\xe1 o respectivo auto de infra\xe7\xe3o de tr\xe2nsito (AIT) e aplicar\xe1 as medidas administrativas cab\xedveis, conforme os procedimentos estabelecidos no MBFT.\n\n(Nota: Devido \xe0 grande extens\xe3o do MBFT, consulte o PDF oficial ou o aplicativo Senatran para buscar fichas espec\xedficas de enquadramento.)"},504,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao960Text",{enumerable:!0,get:function(){return s}});const s="RESOLU\xc7\xc3O CONTRAN N\xba 960, DE 17 DE MAIO DE 2022\n\nDisp\xf5e sobre os requisitos de seguran\xe7a de vidros de seguran\xe7a e crit\xe9rios para aplica\xe7\xe3o de inscri\xe7\xf5es, pictogramas e pel\xedculas nas \xe1reas envidra\xe7adas dos ve\xedculos automotores, de acordo com o inciso III do art. 111 do CTB.\n\nArt. 3\xba A transmiss\xe3o luminosa das \xe1reas envidra\xe7adas n\xe3o poder\xe1 ser inferior a 70% para os vidros dos para-brisas e das demais \xe1reas envidra\xe7adas indispens\xe1veis \xe0 dirigibilidade do ve\xedculo.\n\n\xa7 1\xba Ficam exclu\xeddos dos limites fixados no caput os vidros que n\xe3o interferem nas \xe1reas envidra\xe7adas indispens\xe1veis \xe0 dirigibilidade do ve\xedculo. Para estes vidros, a transmiss\xe3o luminosa n\xe3o poder\xe1 ser inferior a 28%.\n\nArt. 8\xba O uso de pel\xedculas n\xe3o refletivas nas \xe1reas envidra\xe7adas dos ve\xedculos depender\xe1 de chancela que contenha o \xedndice de transmiss\xe3o luminosa e a marca do instalador.\n\nArt. 10. O descumprimento do disposto nesta Resolu\xe7\xe3o sujeita o infrator \xe0s penalidades previstas no art. 230, inciso XVI, do CTB (Infra\xe7\xe3o Grave - Multa e Reten\xe7\xe3o do Ve\xedculo)."},505,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao916Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 916, DE 28 DE MAR\xc7O DE 2022\n\nDisp\xf5e sobre a concess\xe3o de c\xf3digo de marca/modelo/vers\xe3o para ve\xedculos e sobre as modifica\xe7\xf5es de ve\xedculos previstas nos arts. 97, 98 e 114 do CTB.\n\nArt. 5\xba As modifica\xe7\xf5es em ve\xedculos devem ser precedidas de autoriza\xe7\xe3o da autoridade executiva de tr\xe2nsito do Estado ou do Distrito Federal.\n\n\xa7 1\xba Quando a modifica\xe7\xe3o exigir a realiza\xe7\xe3o de inspe\xe7\xe3o de seguran\xe7a veicular para emiss\xe3o do Certificado de Seguran\xe7a Veicular (CSV), a autoridade executiva de tr\xe2nsito exigir\xe1 a apresenta\xe7\xe3o de CSV emitido por Institui\xe7\xe3o T\xe9cnica Licenciada (ITL).\n\nArt. 6\xba A modifica\xe7\xe3o da suspens\xe3o do ve\xedculo (rebaixamento ou eleva\xe7\xe3o) \xe9 permitida, desde que atenda aos requisitos do Anexo desta Resolu\xe7\xe3o, devendo o ve\xedculo passar por inspe\xe7\xe3o e obter o CSV.\n\nArt. 7\xba \xc9 proibida a altera\xe7\xe3o da cor do ve\xedculo sem pr\xe9via autoriza\xe7\xe3o. Considera-se altera\xe7\xe3o de cor quando a \xe1rea modificada for superior a 50% da \xe1rea do ve\xedculo (excluindo \xe1reas envidra\xe7adas).\n\nInfra\xe7\xf5es relacionadas:\nArt. 230, VII do CTB: Conduzir o ve\xedculo com a cor ou caracter\xedstica alterada. (Infra\xe7\xe3o Grave, Multa e Reten\xe7\xe3o do ve\xedculo para regulariza\xe7\xe3o)."},506,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao432Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 432, DE 23 DE JANEIRO DE 2013 (Atualizada)\n\nDisp\xf5e sobre os procedimentos a serem adotados pelas autoridades de tr\xe2nsito e seus agentes na fiscaliza\xe7\xe3o do consumo de \xe1lcool ou de outra subst\xe2ncia psicoativa que determine depend\xeancia.\n\nArt. 3\xba A confirma\xe7\xe3o da altera\xe7\xe3o da capacidade psicomotora em raz\xe3o da influ\xeancia de \xe1lcool ou de outra subst\xe2ncia psicoativa dar-se-\xe1 por meio de pelo menos um dos seguintes procedimentos:\nI - exame de sangue;\nII - exames realizados por laborat\xf3rios especializados;\nIII - teste em aparelho destinado \xe0 medi\xe7\xe3o do teor alco\xf3lico no ar alveolar (etil\xf4metro);\nIV - verifica\xe7\xe3o dos sinais que indiquem a altera\xe7\xe3o da capacidade psicomotora do condutor.\n\nArt. 5\xba O condutor que for submetido ao teste em etil\xf4metro, e o aparelho registrar medida igual ou superior a 0,05 miligrama de \xe1lcool por litro de ar alveolar expirado (0,05 mg/L), descontado o erro m\xe1ximo admiss\xedvel, estar\xe1 sujeito \xe0 infra\xe7\xe3o do art. 165 do CTB.\n\nArt. 7\xba O crime de tr\xe2nsito (art. 306) caracteriza-se pela medi\xe7\xe3o igual ou superior a 0,34 miligrama de \xe1lcool por litro de ar alveolar expirado (0,34 mg/L), descontado o erro m\xe1ximo admiss\xedvel.\n\nRecusa (Art. 165-A CTB): A recusa ao teste do etil\xf4metro ou qualquer exame cl\xednico caracteriza infra\xe7\xe3o grav\xedssima, com multa (multiplicada por 10) e suspens\xe3o do direito de dirigir por 12 meses."},507,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao923Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 923, DE 28 DE MAR\xc7O DE 2022\n\nDisp\xf5e sobre o exame toxicol\xf3gico de larga janela de detec\xe7\xe3o, em amostra querat\xednica, para a habilita\xe7\xe3o, renova\xe7\xe3o ou mudan\xe7a para as categorias C, D e E.\n\nArt. 2\xba O exame toxicol\xf3gico de larga janela de detec\xe7\xe3o visa a verificar o consumo de subst\xe2ncias psicoativas que, comprovadamente, comprometam a capacidade de dire\xe7\xe3o, e dever\xe1 ter janela de detec\xe7\xe3o m\xednima de 90 (noventa) dias.\n\nArt. 3\xba A coleta do material biol\xf3gico dever\xe1 ser realizada em laborat\xf3rios credenciados pela SENATRAN.\n\nO descumprimento, especialmente dirigir com o exame toxicol\xf3gico vencido h\xe1 mais de 30 dias (Art. 165-B), acarreta infra\xe7\xe3o grav\xedssima (multiplicada por 5) e suspens\xe3o do direito de dirigir por 3 meses, condicionado o levantamento da suspens\xe3o \xe0 inclus\xe3o no Renach de resultado negativo em novo exame.\n\nNota: As regras de fiscaliza\xe7\xe3o sofreram recentes atualiza\xe7\xf5es com a Resolu\xe7\xe3o 1.009/24 quanto ao cronograma de exig\xeancia de penalidades."},508,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao940Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 940, DE 28 DE MAR\xc7O DE 2022\n\nDisp\xf5e sobre o uso do capacete motocicl\xedstico.\n\nArt. 2\xba \xc9 obrigat\xf3rio, para circular na via p\xfablica, o uso de capacete motocicl\xedstico pelo condutor e passageiro de motocicleta, motoneta, ciclomotor, triciclo motorizado e quadriciclo motorizado.\n\nArt. 3\xba O capacete tem de estar devidamente afixado \xe0 cabe\xe7a pelo conjunto formado pela cinta jugular e engate, por debaixo do maxilar inferior.\n\nArt. 4\xba O capacete motocicl\xedstico deve ser dotado de dispositivo retr\xe1til (viseira) ou estar acompanhado de \xf3culos de prote\xe7\xe3o. No per\xedodo noturno, a viseira ou \xf3culos devem ser no padr\xe3o cristal."},509,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao969Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 969, DE 20 DE JUNHO DE 2022\n\nDisp\xf5e sobre o sistema de Placas de Identifica\xe7\xe3o Veicular (PIV) no padr\xe3o Mercosul.\n\nArt. 3\xba Ap\xf3s o registro no RENAVAM, cada ve\xedculo ser\xe1 identificado por placa veicular padr\xe3o Mercosul, que dever\xe1 conter 7 caracteres alfanum\xe9ricos.\n\nArt. 18. O uso da PIV no padr\xe3o Mercosul \xe9 obrigat\xf3rio para o primeiro emplacamento, mudan\xe7a de categoria, roubo/furto/extravio da placa, ou mudan\xe7a de munic\xedpio/estado.\n\nOs ve\xedculos com placa no padr\xe3o anterior podem continuar circulando at\xe9 que ocorra uma das situa\xe7\xf5es de obrigatoriedade de troca."},510,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao819Text",{enumerable:!0,get:function(){return n}});const n="RESOLU\xc7\xc3O CONTRAN N\xba 819, DE 17 DE MAR\xc7O DE 2021\n\nDisp\xf5e sobre o transporte de crian\xe7as com idade inferior a dez anos que n\xe3o tenham atingido 1,45m de altura.\n\nArt. 2\xba O transporte de crian\xe7a com idade inferior a dez anos que n\xe3o tenha atingido 1,45m de altura deve ser realizado no banco traseiro, com o uso de dispositivo de reten\xe7\xe3o adequado:\nI - beb\xea conforto: crian\xe7as de at\xe9 1 ano de idade;\nII - cadeirinha: crian\xe7as de 1 a 4 anos;\nIII - assento de eleva\xe7\xe3o: crian\xe7as de 4 a 7 anos e meio;\nIV - cinto de seguran\xe7a do ve\xedculo: crian\xe7as com mais de 7 anos e meio at\xe9 10 anos que ainda n\xe3o atingiram 1,45m.\n\nArt. 9\xba O descumprimento sujeita o condutor \xe0 infra\xe7\xe3o grav\xedssima (art. 168 do CTB)."},511,[]);
__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"resolucao798Text",{enumerable:!0,get:function(){return o}});const o="RESOLU\xc7\xc3O CONTRAN N\xba 798, DE 2 DE SETEMBRO DE 2020\n\nDisp\xf5e sobre os requisitos t\xe9cnicos para a fiscaliza\xe7\xe3o da velocidade de ve\xedculos automotores, reboques e semirreboques.\n\nArt. 3\xba Os medidores de velocidade devem ser do tipo:\nI - fixo (controlador ou redutor);\nII - port\xe1til;\nIII - est\xe1tico;\nIV - m\xf3vel.\n\nArt. 6\xba A fiscaliza\xe7\xe3o deve ser ostensiva. \xc9 proibido o uso de equipamentos sem sinaliza\xe7\xe3o pr\xe9via (placas R-19) indicando o limite de velocidade da via ou o uso de medidores de velocidade ocultos ou camuflados.\n\nA autua\xe7\xe3o de velocidade tem margem de toler\xe2ncia (erro m\xe1ximo admitido) de 7 km/h para velocidades at\xe9 100 km/h, e de 7% para velocidades acima de 100 km/h."},512,[]);
